const aiText = $input.first().json.choices[0].message.content.trim();
const chatId = $('Extrair Mensagem').first().json.chatId;
const from = $('Extrair Mensagem').first().json.from;

let parsed;
try {
  // Remove blocos de markdown se existirem
  const clean = aiText.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = { acao: 'ajuda' };
}

parsed.chatId = chatId;
parsed.operador = from + ' (Telegram)';

return [{ json: parsed }];

// Formata resposta da movimentação para o Telegram
const result = $input.first().json;
const chatId = $('Parsear Resposta IA').first().json.chatId;

let texto;
if (result.sucesso) {
  texto = result.mensagem;
  if (result.estoque) {
    texto += `\n\n📦 *Estoque atual de ${result.estoque.nome}:*`;
    texto += `\n• Total: ${result.estoque.qtd_total}`;
    texto += `\n• Disponível: ${result.estoque.qtd_disponivel}`;
    texto += `\n• Status: ${result.estoque.status}`;
  }
} else {
  texto = `❌ Erro: ${result.error}`;
}

return [{ json: { chatId, texto } }];

// Formata resposta de consulta para o Telegram
const result = $input.first().json;
const chatId = $('Parsear Resposta IA').first().json.chatId;

let texto = '📦 *Consulta de Estoque:*\n\n';

if (result.equipamentos && result.equipamentos.length > 0) {
  result.equipamentos.forEach(e => {
    texto += `*${e.nome}* (${e.categoria})\n`;
    texto += `  • Total: ${e.qtd_total || 0} | Disponível: ${e.qtd_disponivel || 0}\n`;
    texto += `  • Status: ${e.status}\n\n`;
  });
} else {
  texto = '⚠️ Nenhum equipamento encontrado com esse nome.';
}

return [{ json: { chatId, texto } }];
